import chalk from "chalk";
import fs from "fs-extra";
import ora from "ora";
import path, { dirname } from "path";
import { fileURLToPath } from "url";

const __filename = fileURLToPath(import.meta.url);
const __dirname = dirname(__filename);

export default async function () {
  let spinner = ora("Memeriksa instalasi").start();

  // Cek apakah transtrack-ui terinstal
  let packageJson = JSON.parse(
    fs.readFileSync(path.resolve(process.cwd(), "package.json"), "utf8")
  );

  if (!packageJson.dependencies?.["@transtrack/ui"]) {
    spinner.fail("transtrack-ui belum terinstal");
    console.log(chalk.yellow("\nSilakan install terlebih dahulu:"));
    console.log(chalk.cyan("npm install transtrack-ui"));
    process.exit(1);
  }

  spinner.succeed("transtrack-ui terinstal");

   spinner = ora("Memeriksa struktur proyek").start();

  // Cek apakah package.json ada di direktori saat ini
  if (!fs.existsSync("package.json")) {
    spinner.fail(
      "package.json tidak ditemukan. Jalankan perintah ini di direktori proyek Nuxt."
    );
    process.exit(1);
  }

  // Baca package.json untuk verifikasi
   packageJson = JSON.parse(
    fs.readFileSync(path.resolve(process.cwd(), "package.json"), "utf8")
  );

  // Cek instalasi transtrack-ui
  if (!packageJson.dependencies?.["@transtrack/ui"]) {
    spinner.fail("transtrack-ui belum terinstal");
    console.log(chalk.yellow("\nSilakan install terlebih dahulu:"));
    console.log(chalk.cyan("npm install transtrack-ui"));
    process.exit(1);
  }

  spinner.succeed("transtrack-ui terinstal");

  // Cek instalasi Nuxt
  if (!packageJson.dependencies?.nuxt && !packageJson.devDependencies?.nuxt) {
    spinner.warn(
      "Sepertinya ini bukan proyek Nuxt. Pastikan Nuxt sudah terinstal."
    );
  } else {
    spinner.succeed("Struktur proyek Nuxt terverifikasi");
  }

  // Buat direktori component jika belum ada
  const componentsDir = "components/ui";
  if (!fs.existsSync(componentsDir)) {
    spinner.text = "Membuat direktori component";
    spinner.start();
    fs.ensureDirSync(componentsDir);
    spinner.succeed(`Direktori component dibuat: ${componentsDir}`);
  }

  // Inisialisasi types/element.ts
  const typesDir = "types";
  const elementTypesFile = path.join(typesDir, "element.ts");
  if (!fs.existsSync(elementTypesFile)) {
    spinner.text = "Membuat file types/element.ts";
    spinner.start();
    await fs.ensureDir(typesDir);
    await fs.copy(
      path.resolve(__dirname, "../../types/element.ts"),
      elementTypesFile
    );
    spinner.succeed("File types/element.ts berhasil dibuat");
  }

  // Inisialisasi composables/modal.ts
  const composablesDir = "composables";
  const modalComposableFile = path.join(composablesDir, "modal.ts");
  if (!fs.existsSync(modalComposableFile)) {
    spinner.text = "Membuat file composables/modal.ts";
    spinner.start();
    await fs.ensureDir(composablesDir);
    await fs.copy(
      path.resolve(__dirname, "../../composables/modal.ts"),
      modalComposableFile
    );
    spinner.succeed("File composables/modal.ts berhasil dibuat");
  }

  // Inisialisasi utils/ui.ts
  const utilsDir = "utils";
  const uiUtilsFile = path.join(utilsDir, "ui.ts");
  if (!fs.existsSync(uiUtilsFile)) {
    spinner.text = "Membuat file utils/ui.ts";
    spinner.start();
    await fs.ensureDir(utilsDir);
    await fs.copy(
      path.resolve(__dirname, "../../utils/ui.ts"),
      uiUtilsFile
    );
    spinner.succeed("File utils/ui.ts berhasil dibuat");
  }

  console.log(chalk.green("\n✅ Inisialisasi selesai!"));
  console.log(`
Selanjutnya, Anda dapat menambahkan component dengan:
  ${chalk.cyan("transtrack-ui add [nama-component]")}
  `);
}
